package v2

import (
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

// +genclient
// +genclient:nonNamespaced
// +k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object
// +kubebuilder:resource:categories={cilium},singular="ciliumpolicyquota",path="ciliumpolicyquotas",scope="Cluster",shortName={cpq}
// +kubebuilder:object:root=true
// +kubebuilder:storageversion
// +deepequal-gen=false

// CiliumPolicyQuota defines per-namespace limits on the number of
// CiliumNetworkPolicy resources to prevent policy sprawl.
type CiliumPolicyQuota struct {
	// +deepequal-gen=false
	metav1.TypeMeta `json:",inline"`
	// +deepequal-gen=false
	// +kubebuilder:validation:Optional
	metav1.ObjectMeta `json:"metadata,omitempty"`

	// Spec defines the desired policy quota specification.
	//
	// +kubebuilder:validation:Required
	Spec CiliumPolicyQuotaSpec `json:"spec"`
}

// CiliumPolicyQuotaSpec defines the specification for policy quotas.
type CiliumPolicyQuotaSpec struct {
	// MaxPoliciesPerNamespace defines the maximum number of CiliumNetworkPolicy
	// resources allowed per namespace. A value of 0 means unlimited.
	//
	// +kubebuilder:validation:Required
	// +kubebuilder:validation:Minimum=0
	MaxPoliciesPerNamespace int32 `json:"maxPoliciesPerNamespace"`
}

// +k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object
// +deepequal-gen=false

// CiliumPolicyQuotaList is a collection of CiliumPolicyQuota resources.
type CiliumPolicyQuotaList struct {
	// +deepequal-gen=false
	metav1.TypeMeta `json:",inline"`
	// +deepequal-gen=false
	metav1.ListMeta `json:"metadata,omitempty"`
	Items           []CiliumPolicyQuota `json:"items"`
}

// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package quota

import (
	"context"
	"fmt"
	"log/slog"
	"sync"

	"github.com/cilium/hive/cell"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

// PolicyQuotaController watches CiliumNetworkPolicy resources and enforces
// per-namespace quotas to prevent policy sprawl in multi-tenant clusters.
type PolicyQuotaController struct {
	log                    *slog.Logger
	ciliumNetworkPolicies  resource.Resource[*cilium_v2.CiliumNetworkPolicy]
	maxPoliciesPerNs       int
	namespacePolicyCounts  map[string]int
	namespacePoliciesMutex sync.RWMutex
}

// NewPolicyQuotaController creates a new PolicyQuotaController instance.
func NewPolicyQuotaController(
	log *slog.Logger,
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		log:                   log,
		ciliumNetworkPolicies: ciliumNetworkPolicies,
		maxPoliciesPerNs:      maxPerNamespace,
		namespacePolicyCounts: make(map[string]int),
	}
}

// Run starts the controller loop. It watches for CiliumNetworkPolicy events
// and tracks policy counts per namespace.
func (c *PolicyQuotaController) Run(ctx context.Context) error {
	c.log.InfoContext(ctx, "Starting PolicyQuotaController")

	events := c.ciliumNetworkPolicies.Events(ctx)
	for {
		select {
		case <-ctx.Done():
			c.log.InfoContext(ctx, "Stopping PolicyQuotaController")
			return nil
		case event, ok := <-events:
			if !ok {
				return fmt.Errorf("policy events channel closed")
			}

			switch event.Kind {
			case resource.Upsert:
				c.handlePolicyUpsert(event.Object)
				event.Done(nil)
			case resource.Delete:
				c.handlePolicyDelete(event.Object)
				event.Done(nil)
			case resource.Sync:
				c.log.DebugContext(ctx, "PolicyQuotaController synced with API server")
				event.Done(nil)
			}
		}
	}
}

// handlePolicyUpsert processes an upserted CiliumNetworkPolicy.
func (c *PolicyQuotaController) handlePolicyUpsert(policy *cilium_v2.CiliumNetworkPolicy) {
	c.namespacePoliciesMutex.Lock()
	defer c.namespacePoliciesMutex.Unlock()

	ns := policy.GetNamespace()
	c.namespacePolicyCounts[ns]++

	c.log.DebugContext(
		context.Background(),
		"Policy upserted",
		logfields.Namespace, ns,
		logfields.Name, policy.GetName(),
		"policyCount", c.namespacePolicyCounts[ns],
	)
}

// handlePolicyDelete processes a deleted CiliumNetworkPolicy.
func (c *PolicyQuotaController) handlePolicyDelete(policy *cilium_v2.CiliumNetworkPolicy) {
	c.namespacePoliciesMutex.Lock()
	defer c.namespacePoliciesMutex.Unlock()

	ns := policy.GetNamespace()
	if count, exists := c.namespacePolicyCounts[ns]; exists && count > 0 {
		c.namespacePolicyCounts[ns]--
	}

	c.log.DebugContext(
		context.Background(),
		"Policy deleted",
		logfields.Namespace, ns,
		logfields.Name, policy.GetName(),
		"policyCount", c.namespacePolicyCounts[ns],
	)
}

// CheckQuota checks if the given namespace is within its policy quota.
// It returns an error if the quota is exceeded.
func (c *PolicyQuotaController) CheckQuota(namespace string) error {
	if c.maxPoliciesPerNs <= 0 {
		// 0 means unlimited
		return nil
	}

	c.namespacePoliciesMutex.RLock()
	count := c.namespacePolicyCounts[namespace]
	c.namespacePoliciesMutex.RUnlock()

	if count >= c.maxPoliciesPerNs {
		return fmt.Errorf(
			"namespace %q has reached its policy quota limit: %d/%d",
			namespace,
			count,
			c.maxPoliciesPerNs,
		)
	}

	return nil
}

// GetNamespacePolicyCount returns the current policy count for a namespace.
func (c *PolicyQuotaController) GetNamespacePolicyCount(namespace string) int {
	c.namespacePoliciesMutex.RLock()
	defer c.namespacePoliciesMutex.RUnlock()

	return c.namespacePolicyCounts[namespace]
}

// PolicyQuotaControllerParams is the parameter struct for hive dependency injection.
type PolicyQuotaControllerParams struct {
	cell.In

	Log                   *slog.Logger
	CiliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]
}

// PolicyQuotaControllerConfig defines configuration for the PolicyQuotaController.
type PolicyQuotaControllerConfig struct {
	MaxPoliciesPerNamespace int
}

// DefaultPolicyQuotaConfig provides default configuration values.
var DefaultPolicyQuotaConfig = PolicyQuotaControllerConfig{
	MaxPoliciesPerNamespace: 100,
}

// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package quota

import (
	"context"
	"log/slog"
	"testing"

	"github.com/stretchr/testify/require"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
)

// mockResource implements resource.Resource[*cilium_v2.CiliumNetworkPolicy] for testing
type mockResource struct {
	events chan resource.Event[*cilium_v2.CiliumNetworkPolicy]
}

func (m *mockResource) Events(ctx context.Context, opts ...resource.EventsOpt) <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy] {
	return m.events
}

func (m *mockResource) Store(ctx context.Context) (resource.Store[*cilium_v2.CiliumNetworkPolicy], error) {
	return nil, nil
}

func (m *mockResource) Observe(ctx context.Context, opts ...resource.EventsOpt) <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy] {
	return m.Events(ctx, opts...)
}

func newMockResource() *mockResource {
	return &mockResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy], 100),
	}
}

func newTestPolicy(name, namespace string) *cilium_v2.CiliumNetworkPolicy {
	return &cilium_v2.CiliumNetworkPolicy{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "cilium.io/v2",
			Kind:       "CiliumNetworkPolicy",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name:      name,
			Namespace: namespace,
		},
	}
}

func TestPolicyQuotaController_CheckQuotaUnlimited(t *testing.T) {
	log := slog.Default()
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(log, mockRes, 0) // 0 = unlimited

	// Even with many policies, unlimited quota should not error
	err := controller.CheckQuota("default")
	require.NoError(t, err)
}

func TestPolicyQuotaController_CheckQuotaWithinLimit(t *testing.T) {
	log := slog.Default()
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(log, mockRes, 5)

	// Add 3 policies
	for i := 1; i <= 3; i++ {
		controller.handlePolicyUpsert(newTestPolicy("policy-"+string(rune(i)), "default"))
	}

	// Should not error when within quota
	err := controller.CheckQuota("default")
	require.NoError(t, err)
}

func TestPolicyQuotaController_CheckQuotaExceeded(t *testing.T) {
	log := slog.Default()
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(log, mockRes, 3)

	// Add 3 policies (at the limit)
	for i := 1; i <= 3; i++ {
		controller.handlePolicyUpsert(newTestPolicy("policy-"+string(rune(i)), "default"))
	}

	// Should error when at or over quota
	err := controller.CheckQuota("default")
	require.Error(t, err)
	require.Contains(t, err.Error(), "reached its policy quota limit")
}

func TestPolicyQuotaController_NamespaceSeparation(t *testing.T) {
	log := slog.Default()
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(log, mockRes, 2)

	// Add policies to different namespaces
	controller.handlePolicyUpsert(newTestPolicy("policy-1", "ns1"))
	controller.handlePolicyUpsert(newTestPolicy("policy-2", "ns1"))
	controller.handlePolicyUpsert(newTestPolicy("policy-1", "ns2"))

	// ns1 should be at quota
	err := controller.CheckQuota("ns1")
	require.Error(t, err)

	// ns2 should be within quota
	err = controller.CheckQuota("ns2")
	require.NoError(t, err)

	// Verify counts
	require.Equal(t, 2, controller.GetNamespacePolicyCount("ns1"))
	require.Equal(t, 1, controller.GetNamespacePolicyCount("ns2"))
}

func TestPolicyQuotaController_PolicyDeletion(t *testing.T) {
	log := slog.Default()
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(log, mockRes, 2)

	policy1 := newTestPolicy("policy-1", "default")
	policy2 := newTestPolicy("policy-2", "default")

	// Add two policies (at the limit)
	controller.handlePolicyUpsert(policy1)
	controller.handlePolicyUpsert(policy2)

	// Should be at quota
	err := controller.CheckQuota("default")
	require.Error(t, err)

	// Delete one policy
	controller.handlePolicyDelete(policy1)

	// Should now be within quota
	err = controller.CheckQuota("default")
	require.NoError(t, err)

	// Verify count decreased
	require.Equal(t, 1, controller.GetNamespacePolicyCount("default"))
}

func TestPolicyQuotaController_GetNamespacePolicyCount(t *testing.T) {
	log := slog.Default()
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(log, mockRes, 10)

	// Initially empty
	require.Equal(t, 0, controller.GetNamespacePolicyCount("default"))

	// Add policies
	for i := 1; i <= 5; i++ {
		controller.handlePolicyUpsert(newTestPolicy("policy-"+string(rune(i)), "default"))
	}

	require.Equal(t, 5, controller.GetNamespacePolicyCount("default"))
}

func TestPolicyQuotaController_MultipleNamespaces(t *testing.T) {
	log := slog.Default()
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(log, mockRes, 3)

	namespaces := []string{"ns1", "ns2", "ns3"}

	// Add policies to multiple namespaces
	for i, ns := range namespaces {
		for j := 1; j <= 2; j++ {
			controller.handlePolicyUpsert(
				newTestPolicy("policy-"+string(rune(j)), ns),
			)
		}
		require.Equal(t, 2, controller.GetNamespacePolicyCount(ns), "namespace %s should have 2 policies", ns)
	}

	// All namespaces should be within quota
	for _, ns := range namespaces {
		err := controller.CheckQuota(ns)
		require.NoError(t, err, "namespace %s should be within quota", ns)
	}

	// Add one more policy to each to reach quota
	for _, ns := range namespaces {
		controller.handlePolicyUpsert(newTestPolicy("policy-3", ns))
	}

	// All should now be at quota (error)
	for _, ns := range namespaces {
		err := controller.CheckQuota(ns)
		require.Error(t, err, "namespace %s should be at quota", ns)
	}
}

func TestNewPolicyQuotaController(t *testing.T) {
	log := slog.Default()
	mockRes := newMockResource()
	maxPolicies := 50

	controller := NewPolicyQuotaController(log, mockRes, maxPolicies)

	require.NotNil(t, controller)
	require.Equal(t, maxPolicies, controller.maxPoliciesPerNs)
	require.NotNil(t, controller.namespacePolicyCounts)
}

func TestPolicyQuotaController_ThreadSafety(t *testing.T) {
	log := slog.Default()
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(log, mockRes, 1000)

	// Simulate concurrent operations
	done := make(chan bool)

	// Add policies concurrently
	for i := 0; i < 10; i++ {
		go func(id int) {
			for j := 0; j < 10; j++ {
				controller.handlePolicyUpsert(
					newTestPolicy("policy-"+string(rune(j)), "default"),
				)
			}
			done <- true
		}(i)
	}

	// Wait for all goroutines to complete
	for i := 0; i < 10; i++ {
		<-done
	}

	// Verify the operation completed without panic
	require.Greater(t, controller.GetNamespacePolicyCount("default"), 0)
}

func TestPolicyQuotaController_ExceedQuotaErrorMessage(t *testing.T) {
	log := slog.Default()
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(log, mockRes, 2)

	ns := "test-namespace"
	for i := 1; i <= 2; i++ {
		controller.handlePolicyUpsert(newTestPolicy("policy-"+string(rune(i)), ns))
	}

	err := controller.CheckQuota(ns)
	require.Error(t, err)
	require.Contains(t, err.Error(), "test-namespace")
	require.Contains(t, err.Error(), "quota limit")
	require.Contains(t, err.Error(), "2/2")
}

func TestCiliumPolicyQuotaType(t *testing.T) {
	quota := &cilium_v2.CiliumPolicyQuota{
		ObjectMeta: metav1.ObjectMeta{
			Name: "test-quota",
		},
		Spec: cilium_v2.CiliumPolicyQuotaSpec{
			MaxPoliciesPerNamespace: 50,
		},
	}

	require.NotNil(t, quota)
	require.Equal(t, "test-quota", quota.ObjectMeta.Name)
	require.Equal(t, int32(50), quota.Spec.MaxPoliciesPerNamespace)
}

func TestCiliumPolicyQuotaList(t *testing.T) {
	quotaList := &cilium_v2.CiliumPolicyQuotaList{
		Items: []cilium_v2.CiliumPolicyQuota{
			{
				ObjectMeta: metav1.ObjectMeta{Name: "quota-1"},
				Spec: cilium_v2.CiliumPolicyQuotaSpec{MaxPoliciesPerNamespace: 50},
			},
			{
				ObjectMeta: metav1.ObjectMeta{Name: "quota-2"},
				Spec: cilium_v2.CiliumPolicyQuotaSpec{MaxPoliciesPerNamespace: 100},
			},
		},
	}

	require.Equal(t, 2, len(quotaList.Items))
	require.Equal(t, int32(50), quotaList.Items[0].Spec.MaxPoliciesPerNamespace)
	require.Equal(t, int32(100), quotaList.Items[1].Spec.MaxPoliciesPerNamespace)
}

